{{-- resources/views/perfil.blade.php --}}

<!DOCTYPE html>
<html>
<body>
    {{-- Exibir variável (com escape HTML automático) --}}
    <h1>Olá, {{ $nome }}!</h1>

    {{-- Sem escape (cuidado com XSS!) --}}
    <p>{!! $htmlConfiavel !!}</p>

    {{-- Comentário Blade (não aparece no HTML final) --}}
    {{-- Este comentário não é enviado ao navegador --}}
</body>
</html>

// No Controller
public function perfil()
{
    return view('perfil', [
        'nome' => 'Ana Silva',
        'email' => 'ana@exemplo.com',
    ]);

    // Ou usando with()
    return view('perfil')->with('nome', 'Ana Silva');

    // Ou compact() — quando variável tem mesmo nome que chave
    $nome = 'Ana Silva';
    return view('perfil', compact('nome'));
}
